    ['Omens'] = {
        id = 22,
        start_npc = 'Waoud/Raubahn',
        start_zone = 'Aht Urhgan Whitegate',
        start_pos = 'J-10',
        description = 'The only choice you have left is to forge ahead in the quest for power, or face your own destruction... If ambition still fuels your soul, head to the Navukgo Execution Chamber and obliterate the monstrous flan!',
        reward = 'Magus Charuqs',
        fame = 'Treasures of Aht Urhgan',
        fame_level = nil,
        title = 'Immortal Lion',
        repeatable = 'No',
        previous = {'Beginnings'},
        next = {'Transformations'},
        requirements = {
            {name = '[Key Item] Sealed Immortal envelope', count = 1},
        },
        walkthrough = '1. (Wait one in game day since completing the last quest and re-zone into Aht Urhgan Whitegate if you haven\'t already.)\n2. Speak to Waoud to begin the quest.\n3. Raubahn will direct you to find and kill a Flan in the Navukgo Execution Chamber.\n   - Travel via the Home Point in the part of Mount Zhayolm just outside the chamber or the Mount Zhayolm Unity warps (level 128 or 135) is quickest.\n   - You do not have to be on Blue Mage to enter or complete this BCNM.\n4. When in the Navukgo Execution Chamber, examine the Decorative Bronze Gate to start a BC fight.\n   - Up to 18 people can enter, but more people will cause more Immortal Flans to spawn.\n   - Trust Magic CAN be used in this battlefield.\n5. Return to Aht Urhgan Whitegate and speak to Waoud.\n6. You will be given a Sealed Immortal envelope\n7. Deliver the envelope to Lathuya @  Aht Urhgan Whitegate F-8, on the second floor inside the stall.\n8. Zone into Wajaom Woodlands from Aht Urhgan Whitegate (G/H-10 Stairwell), then head toward the south and zone into the Aydeewa Subterrane entrance at (K-9). There are no enemies in this small tunnel. (There IS a Phlebotomic Slug on upper step that can be pulled, but will not aggro). Examine the unnamed target by the pond at (H-7) for a cutscene.\n9. Return to Aht Urhgan Whitegate and speak to Lathuya.',
        notes = nil,
    },
    ['Operation Teatime'] = {
        id = 28,
        start_npc = 'Iruki-Waraki',
        start_zone = 'Aht Urhgan Whitegate',
        start_pos = 'K-9',
        description = 'Iruki-Waraki has formed a plan to reclaim his Automaton! Go to Nashmau and help him enact his plan.',
        reward = 'Pup. Churidars',
        fame = 'Aht Urhgan',
        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = {'The Wayward Automaton'},
        next = {'Puppetmaster Blues'},
        requirements = {
            {name = 'Sleeping Potion', count = 1},
            {name = 'Chai', count = 1},
            {name = 'Lamian Fang Key', count = 1},
        },
        walkthrough = '1. Must zone after previous quest in order to start this quest.\n2. Speak with Iruki-Waraki in Aht Urhgan Whitegate for a cut-scene. You\'ll discover that he is trying to get his Automaton back, and has formed a plan.\n3. He gives you a shopping list of items needed to help his plan come to fruition.\n4. You can be on any job from here on.\n   - Obtain the required items: Sleeping Potion x1, Chai x1\n5. Return to Iruki-Waraki and trade him the items for a cut-scene. He then asks you to arrange a meeting with the thief in Nashmau.\n6. Head to Nashmau, and seek out Dnegan for a cut-scene(@H-6 on the second floor).\n7. Warning: Do NOT select the option "Ask about the Automaton" in this cut-scene. Speaking with him will start a cutscene, during which you will be approached by Yafahb.\n   - You will be given 3 chat options: Ask about the Automaton, Ask about getting around Nashmau, or invite the thief to have tea with you. Do not ask about the Automaton!\n   - If you do, you will end the cutscene and be forced to wait a game day before resuming. Choose either of the other options.\n8. The next part of the cutscene takes you to Nashmau Port, and you\'ll see Iruki\'s plan in action. He has set-up a tea shop, and as you approach he asks what you would like to drink.\n9. You are then presented with 3 options. Chai, Coffee or "I\'ll pass, thanks".\n   - Choose either drink. Regardless of your drink choice, Iruki will convince the thief to have Chai.\n     - He will, however, mix up the drinks, leaving you to guess which has the Sleeping Potion inside, and which doesn\'t.\n     - The cup with the "Suspicious Vapour" is the correct choice.\n     - The thief then falls asleep. Iruki then confronts the Automaton, which runs off into the depths of Caedarva Mire.\n10. The next part of this quest is long winded and leaves you stuck in a remote area, so bring either a Warp Ring or an Scroll of Instant Warp.\n11. The final ??? for this quest is located in Caedarva Mire, at (K-5), which is actually part of the Azouph Isle map. However, you will need to travel through Arrapago Reef to reach it.\n12. The quickest way to reef is the Survival Guide to reef.\n13. If you used the survival guide to reef, zone out then grab yourself a Lamian Fang Key and zone into the reef from (I-6). The key can be acquired from a ??? near a pond a short way from the zone.\n   - If you did not use the Survival guide, take the Azouph Isle staging point then head to I-6 for the Lamian Fang Key and then enter reef entrance 1.\n     - Beware of the green "Swamp" water near the Lamian Fang Key as it can spawn a NM or debuff you with weight.\n     - The Jnun near the Lamian Fang Key sleeps during the day and will not aggro.\n     - You can also lockpick the door as a thief with thief tools or farm the key from lamia and draugar\'s inside reef.\n14. For the reef you are going to need Silent Oils and Prism Powders, sub Dancer, or etc.\n15. You\'ll find yourself at (I-11) on the map when you first zone into reef.\n16. Apply Sneak (Status) and Invisible (Status), and run around to the Iron Gate at (J-10). Trade the Lamian Fang Key to open it, and head inside.\n   - From inside, take the north path on this map, and you\'ll reach (J-8) back on the first map. Open the door located there and go through.\n   - Head to J-6 (Caedarva Mire 6)\n     - There is a tunnel entrance at (I-6), not far north from where you are. Head there.\n     - Travel East through that tunnel, until presented with a fork in the road. Take the southern route. And run that way until you zone out into Caedarva Mire.\n17. Once in Caedarva Mire Apply Invisible (Status) then head to K-6 and click the ??? behind the tree.\n   - This area has Mosshorn rams and Elder Treants, so take care not to gain unwanted attention. The ??? you seek is located next to a tree a short distance from the zone.\n18. Enjoy the final cut-scene. Once it is complete you will receive your Puppetry Churidars.',
        notes = nil,
    },
