    ['Promotion: Chief Sergeant'] = {
        id = 96,
        start_npc = 'Abquhbah',
        start_zone = 'Aht Urhgan Whitegate (1-10)',
        start_pos = nil,
        description = 'Abquhbah has asked you to visit the weapon shop in his stead. His heavy sighs have you slightly worried...',
