    ['Promotion: Sergeant Major'] = {
        id = 95,
        start_npc = 'Naja Salaheem',
        start_zone = 'Aht Urhgan Whitegate (1-10)',
        start_pos = nil,
        description = 'You must fultill your duty as a sergeant by training up your subordinates into proper mercenaries.',
        reward = 'SM Wildcat badge\nAccess to SM Assaults',
        fame = 'Aht Urhgan',
        fame_level = '1',
        title = 'Sergeant Major',
        repeatable = nil,
        previous = {'Promotion: Sergeant'},
        next = {'Promotion: Chief Sergeant'},
        requirements = nil,
        walkthrough = 'Naja will require you to successfully complete three mini-games. If you fail any portion, wait one real-life minute and speak to Naja again.\nTrial 1 : Push-ups\n1. In this trial, you must count three NPCs doing push-ups and determine who did the least.\n   - A reliable and low-tech way to do this is use a piece of paper and make a mark in three different sections each time a NPC does a push-up.\n   - It is either one of the three, or none.\nTrial 2 : Sit-ups\n2. In this trial, you must give a "message advancement prompt" with proper timing as the three NPCs do sit-ups. To pass, you must time at least 9 out of 10 advancements prompts correctly.\n   - You must press enter/accept when a sit-up is completely finished.\n     - If your timing is correct, you\'ll hear a sharp whistle. If your timing is off, you\'ll hear a dull whistle. Audio is helpful to confirm correct timing, but is not required.\n     - Correct timing is when the animation is completely finished.\n     - The Windower addon Enternity must be unloaded for this trial, as it will repeatedly queue the advancement prompt.\n   - You can practice indefinitely with Abquhbah.\n   - The real challenge will involve three NPCs with slightly different timings. You must press enter/accept when the slowest NPC finishes.\nTrial 3 : Running\n3. In this final trial, you must give prompts to the three NPCs so that they finish running at the same time.\n   - If a NPC falls behind, quickly select their name from the menu to blow a whistle to make them catch up.\n   - If you select a NPC when they aren\'t behind, you will be penalized and can fail the trial.\n   - After the NPCs have stopped running, select "Not now" to finish the exercise.\nAfter the final trial is complete, speak to Naja to finish your quest.',
        notes = nil,
    },
