    ['The Prince and the Hopper'] = {
        id = 67,
        start_npc = 'Maudaal',
        start_zone = 'Aht Urhgan Whitegate',
        start_pos = 'E-9',
        description = 'You have been hired by Professor Clavauert B Chanoix to accompany him and his guinea toad, Salwa- Molwa, to Mamook where they will conduct research on the elusive Poroggo.',
        reward = 'Chanoix\'s Gorget',
        fame = 'Treasures of Aht Urhgan',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Talk to Maudaal in E-9 of Aht Urhgan Whitegate to start this quest. You will receive a lengthy cutscene upon doing so.\n2. After, you are directed to head to the "secret entrance" to Wajaom Woodlands, G-10/H-10 of Aht Urhgan. Upon zoning, you receive another cutscene.\n3. Reach Mamook by entering the cave at D-12 on the Wajaom Woodlands map or by using the Mamook Survival Guide warp.\n4. Once you\'ve entered, you will find a "Toad\'s Footprint? (J-7), click it for another cutscene.\n5. You must then travel to a small lake inside Mamook, the hallway in the southern part of G-7/H-7.\n   - Cast Invisible and follow the righthand (northern) wall until you reach G-7/H-7, where there are pots of Viscous Liquid.\n   - Drop Invisible, cast Sneak (to avoid aggro from fish) and drink the Viscous Liquid to turn yourself into a Mamool Ja (to avoid aggro from Poroggos).\n     - Note that you will experience a heavy DoT effect while costumed as a Mamool Ja. This CAN kill you.\n   - Now follow the lefthand (southern) wall a short distance and enter the hallway in the southern part of G-7/H-7 that contain the Toad\'s Footprints.\n6. Check the tracks here once for a cutscene. Check them a second time for a fight.\n7. You will spawn a Poroggo Casanova, assisted by Mikiruru‎, Mikiluru‎, Mikirulu‎, Nikilulu, and Mikilulu‎.\n   - They are unable to be slept, even with Elemental Seal.\n   - The helpers are ordinary frog enemies and have very weak attack power and accuracy, but the Casanova may use all normal Poroggo spells/abilities, including Sleepga, Tier IV and Ancient magic, and "Frog Song".\n   - Killing the Casanova will cause all other frogs to disappear and the battle will end.\n   - Mikilulu Cannot be killed but can be brought down to 1% HP\n8. After winning, check the tracks again for yet another cutscene.\n   - You only have to fight it once for it to count for the rest of your party if they are at that stage in the quest.\n9. Return to Whitegate and talk to Maudaal again for the final cutscene and your reward.',
        notes = nil,
    },
    ['The Rider Cometh'] = {
        id = 76,
        start_npc = 'Nashmeira',
        start_zone = 'Imperial Ward',
        start_pos = nil,
        description = 'Ominous rumors circulating among the mercenary ranks speak of Dark Rider sightings deep within the Hazhalm Testing Grounds. Could this occurrence bear any connection to the unsealed spatial distortion? It falls to you to investigate.',
        reward = 'Imperial Gold Piece\nChoice of one:\n:* Pact with Odin\n:* 10,000 gil\nAccess to [Key Item]Stygian Pact phantom gem',
        fame = 'Treasures of Aht Urhgan',
        fame_level = nil,
        title = 'Heir of the Blighted Gloom',
        repeatable = nil,
        previous = nil,
        next = {'Unwavering Resolve'},
        requirements = nil,
        walkthrough = '1. Enter the Walahra Temple in Aht Urhgan Whitegate at (J/K-8) for a cutscene.\n2. Speak to Yoyoroon in Nashmau in (G-6), upper level stalls.  If you speak to Yoyoroon as a Blue Mage, you will have to change jobs and speak to him again. After the cutscene, you will receive a [Key Item]Message from Yoyoroon.\n      - Not Yuyuroon, who is located almost directly in front of Yoyoroon but on the lower level.\n3. Obtain a Timeworn Talisman from Ephramadian Shades in Arrapago Reef or Caedarva Mire.\n   - Recommend using Survival Guide to Caedarva Mire and riding west then south to find Shades there or even further into Arrapago Reef (where you did the Cutter Mission CS\'s)\n   - Alternatively, purchase and use an Arrapago Ring with 100 Imperial standing accolades from Asrahd at Aht Urhgan Whitegate (I-8). It will put you right next to some Ephramadian Shades near the Cutter.\n      - Talismans obtained prior to starting this quest can be used.\n      - Shades may be found west of the Dvucca Isle Staging Point, around (G-10).\n      - Shades may also be found near the Survival Guide for Caedarva Mire.\n4. Trade the Timeworn Talisman and a Sutlac, Irmik Helvasi, or even both to Yoyoroon in Nashmau.  There is a chance that his appraisal of the item will fail. Trading both at once along with the talisman gives the highest chance for success.\n      - The food can be purchased from Fayeewah and Yafaaf at the Shararat Teahouse in Whitegate.\n      - Yoyoroon will not accept Sutlac +1 or Irmik Helvasi +1.\n      - Should the appraisal fail, you will have to obtain another Timeworn Talisman as well as any food items that you traded him.\n5. Should your appraisal succeed, you will have to zone and talk to Yoyoroon again to receive the [Key Item]Talisman of the rebel gods.\n6. Enter the Walahra Temple in Aht Urhgan Whitegate at (J/K-8) for a cutscene to receive the [Key Item]Talisman key.\n   - If you do not get a cutscene, inspect the Imperial Whitegate instead.\n   - NOTE: For any subsequent attempts, you will need to bring a new Talisman of the rebel gods directly to the Imperial Whitegate door (L-8/9).\n7. Enter Hazhalm Testing Grounds and examine the Entry Gate to view a cutscene.\n   - This is the same area as Einherjar. The quickest way is to use the Caedarva Mire Home Point.\n8. Examine the Entry Gate again to enter a BCNM.\n      - Warning: Trust Magic CANNOT be used in this BCNM.\n      - Your opponent will be Odin Prime, he can cast spells like Paralyze, Dispelga, and elemental magic.\n      - Odin Prime can also spawn up to 3 Odin Images.\n      - At a low percentage, Odin can use Zantetsuken if he stays alive for an extended period of time.\n9. After winning the battle, you will enter a cutscene where you will choose your reward.\n10. Examine Imperial Whitegate at Aht Urhgan Whitegate (L-8/9) for a cutscene to complete the quest.\n      - If you receive the Trust quest cutscene for Trust: Nashmeira, finish the cutscene, then re-examine the gate to complete THIS quest.',
        notes = nil,
    },
    ['The Wayward Automaton'] = {
