    ['Totoroon\'s Treasure Hunt'] = {
        id = 18,
        start_npc = 'Totoroon',
        start_zone = 'Nashmau',
        start_pos = 'G-8',
        description = '"Totoroon find soooper-doooper treasooor? A sooperb find!". He will tell you where it is hidden in exchange for something sweet.',
